        summary = exports.join(', ') || firstLines.substring(0, 100);
      }
      // Cap each file summary at 500 chars
      if (summary.length > 500) summary = summary.substring(0, 497) + '...';
      summaryFiles.push({
        path: file.path,
        summary,
        size: content.length
      });
    } else {
      // CSS/JSON/HTML — keep old compact behavior
      const firstLines = content.split('\n').slice(0, 3).join('\n');
      const exports = content.match(/export\s+(default\s+)?(?:function|const|class)\s+(\w+)/g) || [];
      summaryFiles.push({
        path: file.path,
        summary: exports.join(', ') || firstLines.substring(0, 100),
        size: content.length
      });
    }
  }
}

