        const search = innerBlock.substring(0, innerSep);
        const replace = innerBlock.substring(innerSep + '\n=======\n'.length);
        if (fc.includes(search)) {
          fc = fc.replace(search, replace);
          applied++;
        } else {
          const st = search.split('\n').map(l => l.trim()).join('\n');
          const cl = fc.split('\n');
          for (let i = 0; i <= cl.length - search.split('\n').length; i++) {
            if (cl.slice(i, i + search.split('\n').length).map(l => l.trim()).join('\n') === st) {
              cl.splice(i, search.split('\n').length, ...replace.split('\n'));
              fc = cl.join('\n');
              applied++;
              break;
            }
          }
        }
      }
      if (applied > 0) { processedFiles.push({ path: file.path, content: fc }); continue; }
    }
  }
  processedFiles.push(file);
