const sections = {};
if (existingMemory) {
  const positions = [];
  const re = /^## (.+)$/gm;
  let m;
  while ((m = re.exec(existingMemory)) !== null) {
    positions.push({ name: m[1], start: m.index });
  }
  for (let i = 0; i < positions.length; i++) {
    const end = i + 1 < positions.length ? positions[i + 1].start : existingMemory.length;
    sections[positions[i].name] = existingMemory.substring(positions[i].start, end).trim();
  }
}

// ── ITERATION COUNT ──
const existingHistory = sections['Iteration History'] || '';

const existingRuns = existingHistory.split(/(?=### Iteration )/).filter(r => r.trim().startsWith('### Iteration'));
const iterNum = existingRuns.length + 1;


// ── CLASSIFY this run: initial build, bug fix, feature add, or refactor ──

const existingGoalRaw = (sections['Goal'] || '').replace(/^## Goal\n?/, '').trim();
const existingGoal = existingGoalRaw;
const isInitial = iterNum === 1 || (!existingGoal && filesWritten.length > 5);
let runType = 'Update';
if (isInitial) runType = 'Initial Build';
else if (msgLower.match(/fix|error|bug|crash|broken|undefined|not defined|not working/)) runType = 'Bug Fix';
else if (msgLower.match(/add|new|feature|implement|create/)) runType = 'Feature';
else if (msgLower.match(/refactor|clean|reorganize|restructure/)) runType = 'Refactor';
else if (msgLower.match(/style|design|layout|color|theme|css/)) runType = 'Styling';

// ── GOAL: evolves over time — original anchors, refinements accumulate ──
let projectGoal;
if (!existingGoalRaw) {
  // First run — current message IS the goal
  projectGoal = currentMessage.substring(0, 300);
} else {
  // Follow-up run — preserve original goal, append meaningful refinements
  // Split existing into base goal and refinements
  const refinementMarker = '\n\n**Refinements:**';
  const [baseGoal, existingRefinements] = existingGoalRaw.split(refinementMarker);
  const priorRefinements = existingRefinements ? existingRefinements.trim().split('\n').filter(l => l.startsWith('- ')) : [];

  // Only add refinement for feature/styling requests, not pure bug fixes
  const isFeatureOrStyle = msgLower.match(/add|new|feature|implement|create|change|make|style|design|layout|color|theme|bigger|smaller|move|redesign|update|improve/);

  if (isFeatureOrStyle && iterNum > 1) {
    const refinement = '- ' + requestSummary.substring(0, 80) + ' (Iteration ' + iterNum + ')';
    // Avoid duplicate refinements
    if (!priorRefinements.some(r => r.substring(0, 40) === refinement.substring(0, 40))) {
      priorRefinements.push(refinement);
    }
  }

  // Keep last 8 refinements
  const recentRefinements = priorRefinements.slice(-8);
  projectGoal = baseGoal + (recentRefinements.length > 0 ? refinementMarker + '\n' + recentRefinements.join('\n') : '');
}

// ── SUMMARIZE the request (first 120 chars, strip stack traces) ──


// ── BUILD the iteration entry ──
const now = new Date().toISOString().split('T')[0] + ' ' + new Date().toISOString().split('T')[1].substring(0, 5);

let entry = '### Iteration ' + iterNum + ' — ' + runType + ' (' + now + ')\n';
entry += '**Request:** ' + requestSummary + '\n';

// What was done
const taskLines = tasks.map(t => (t.task_id || '?') + ': ' + ((t.description || '').substring(0, 60))).join('; ');
if (taskLines) entry += '**Tasks:** ' + taskLines + '\n';
entry += '**Files:** ' + (filesWritten.length > 0 ? filesWritten.join(', ') : 'none') + '\n';

// Result
const buildStr = buildResult.success ? 'PASSED' : 'FAILED — ' + (buildResult.error || '').substring(0, 60);
entry += '**Result:** Build ' + buildStr;
entry += '\n';

if (!buildResult.success) {
  entry += '**Unresolved:** Build failure — ' + (buildResult.error || '').substring(0, 100) + '\n';
}

// ── KNOWN ISSUES: accumulate across runs, remove fixed ones ──
// Start with existing issues
const existingIssuesRaw = (sections['Known Issues'] || '').replace(/^## Known Issues\n?/, '').trim();
const existingIssueLines = existingIssuesRaw.split('\n').filter(l => l.startsWith('- '));


// Merge: keep existing issues not fixed in this run + add new ones
const fixedFiles = new Set(filesWritten);
const keptIssues = existingIssueLines.filter(line => {
  // If the file mentioned in this issue was modified this run, consider it potentially fixed
  const fileMatch = line.match(/\] ([^\s:]+)/);
  return !fileMatch || !fixedFiles.has(fileMatch[1]);
});
const allIssueSet = new Set([...keptIssues]);

// Validate: only keep issues that reference files that actually exist in the project
const existingPaths = new Set(allFiles.map(f => f.path));
const validatedIssues = [...allIssueSet].filter(line => {
  const fileMatch = line.match(/\] ([^\s:]+)/);
  if (!fileMatch) return true; // keep non-file-specific issues
  return existingPaths.has(fileMatch[1]);
});

let knownIssues = validatedIssues.slice(0, 10).join('\n');
if (!knownIssues || knownIssues === '') knownIssues = 'None — last run was clean.';

// ── ARCHITECTURE: detect once, then preserve ──
let archSection = sections['Architecture'] || '';
if (!archSection) {
  const pkgFile = allFiles.find(f => f.path === 'package.json');
  let framework = 'unknown';
  let deps = [];
  if (pkgFile) {
    try {
      const pkg = JSON.parse(pkgFile.content);
      const allDeps = { ...(pkg.dependencies || {}), ...(pkg.devDependencies || {}) };
      if (allDeps.next) framework = 'Next.js';
      else if (allDeps.vite || allDeps['@vitejs/plugin-react']) framework = 'React + Vite';
      else if (allDeps.express) framework = 'Express';
      else if (allDeps.react) framework = 'React';
      deps = Object.keys(allDeps);
    } catch {}
  }
  archSection = '## Architecture\n- Framework: ' + framework + '\n- Key deps: ' + deps.slice(0, 8).join(', ') + '\n- File count: ' + allFiles.length;
} else {
  // Update file count
  archSection = archSection.replace(/File count: \d+/, 'File count: ' + allFiles.length);
}

// ── COMPONENT CONTRACTS: extract from source files ──
let contractsSection = '';
const contractLines = [];
const tsFiles = allFiles.filter(f => f.path.match(/\.(ts|tsx)$/) && f.content);
for (const file of tsFiles) {
  const content = file.content;
  // Find contract interfaces: exported ones with known suffixes, plus createContext<T> referenced ones
  const referencedTypes = new Set();
  const ctxMatch = content.match(/createContext<(\w+)/);
  if (ctxMatch) referencedTypes.add(ctxMatch[1]);
  const knownSuffixes = /(?:Props|Type|Context|State|Config)$/;

  const ifaceRe = /(?:export\s+)?(?:interface|type)\s+(\w+)\s*[{=]/g;
  let ifMatch;
  while ((ifMatch = ifaceRe.exec(content)) !== null) {
    const name = ifMatch[1];
    const isExported = content.substring(Math.max(0, ifMatch.index - 10), ifMatch.index).includes('export');
    if (!isExported && !referencedTypes.has(name) && !knownSuffixes.test(name)) continue;
    const name = ifMatch[1];
    // Extract properties using bracket-depth counter
    const startIdx = content.indexOf('{', ifMatch.index);
    if (startIdx === -1) continue;
    let depth = 0;
    let endIdx = startIdx;
    for (let ci = startIdx; ci < content.length; ci++) {
      if (content[ci] === '{') depth++;
      else if (content[ci] === '}') { depth--; if (depth === 0) { endIdx = ci; break; } }
    }
    const body = content.substring(startIdx + 1, endIdx).trim();
    // Extract property names and types (top-level only)
    const props = body.split('\n')
      .map(l => l.trim())
      .filter(l => l && !l.startsWith('//') && !l.startsWith('/*') && l.includes(':'))
      .map(l => l.replace(/;$/, '').trim())
      .slice(0, 8);
    let propsStr = props.join('; ');
    if (body.split('\n').filter(l => l.trim() && l.includes(':')).length > 8) propsStr += '; ...';
    contractLines.push('### ' + file.path + ': ' + name + '\n  ' + propsStr);
  }
  // Find useXxx hook exports with return type
  const hookRe = /export\s+(?:function|const)\s+(use[A-Z]\w*)\s*\([^)]*\)\s*(?::\s*([^\s{]+))?/g;
  let hookMatch;
  while ((hookMatch = hookRe.exec(content)) !== null) {
    const hookName = hookMatch[1];
    const returnType = hookMatch[2] || 'unknown';
    contractLines.push('### ' + file.path + ': ' + hookName + '()\n  returns: ' + returnType);
  }
}
if (contractLines.length > 0) {
  let contractsBody = contractLines.join('\n');
  if (contractsBody.length > 1500) contractsBody = contractsBody.substring(0, 1450) + '\n  [truncated]';
  contractsSection = '## Component Contracts\n' + contractsBody;
}

// ── ASSETS ──
const assets = allFiles
  .filter(f => f.path.match(/\.(png|jpg|jpeg|svg|gif|webp)$/i))
  .map(f => '- ' + f.path).join('\n');

// ── DECISIONS: preserve user-added section ──
const decisionsSection = sections['Decisions'] || '';

// ── KEEP last 5 iterations ──
const recentRuns = [...existingRuns.slice(-4), entry];

// ── ASSEMBLE ──
let mem = '# Project Memory\n\n';
mem += '## Goal\n' + projectGoal + '\n\n';
mem += archSection + '\n\n';
if (contractsSection) mem += contractsSection + '\n\n';
if (decisionsSection) mem += decisionsSection + '\n\n';
mem += '## Known Issues\n' + knownIssues + '\n\n';
mem += '## Iteration History\n' + recentRuns.join('\n') + '\n';
if (assets) mem += '\n## Assets\n' + assets + '\n';

// Cap at 5K (more room for richer entries)
if (mem.length > 8000) mem = mem.substring(0, 7900) + '\n\n[truncated]\n';

// Write via file-api
const FILE_API = ($env.FILE_API_URL || 'http://file-api:3456').replace('http://', '');
const [apiHost, apiPort] = FILE_API.split(':');
const body = JSON.stringify({ files: [{ path: 'memory.md', content: mem }] });
await new Promise((resolve) => {
  const req = http.request({
    hostname: apiHost, port: parseInt(apiPort) || 3456,
    path: '/projects/' + projectId + '/files-batch',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + ($env.FILE_API_TOKEN || ''),
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(body)
    },
    timeout: 10000
  }, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve(d)); });
  req.on('error', () => resolve(''));
  req.on('timeout', () => { req.destroy(); resolve(''); });
  req.write(body); req.end();
});

return [{ json: $json }];

