let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
if (content.length < 50 && reasoning.length > 50) {
  content = reasoning.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
  if (content.includes('</think>')) content = content.split('</think>').pop().trim();
}

const files = [];
const seen = new Set();
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
const projectId = staticData._currentProjectId || $('Extract Input').first().json.project_id || 'unknown';

// Parse SEARCH/REPLACE blocks — lastIndexOf for =======
const edits = [];
const blockRe = /(?:FILE:|###)?\s*([\w.\/-]+(?:\.[\w]+))\s*\n<<<<<<< SEARCH\n([\s\S]*?)\n>>>>>>> REPLACE/g;
let bm;
while ((bm = blockRe.exec(content)) !== null) {
  const path = bm[1].trim();
  const blockContent = bm[2];
  const lastSep = blockContent.lastIndexOf('\n=======\n');
  if (lastSep === -1) continue;
  const search = blockContent.substring(0, lastSep);
  const replace = blockContent.substring(lastSep + '\n=======\n'.length);
  edits.push({ path, search, replace });
}

// Parse full file blocks
const fileRe = /###\s+([\w.\/-]+\.(?:ts|tsx|js|jsx|json|css|html))\s*\n```[\w]*\n([\s\S]*?)```/g;
let fm;
while ((fm = fileRe.exec(content)) !== null) {
  if (!seen.has(fm[1].trim())) { seen.add(fm[1].trim()); files.push({ path: fm[1].trim(), content: fm[2] }); }
}

// Apply edits
const editsByFile = {};
for (const e of edits) { if (!editsByFile[e.path]) editsByFile[e.path] = []; editsByFile[e.path].push(e); }
for (const [p, fileEdits] of Object.entries(editsByFile)) {
  if (seen.has(p)) continue;
  const existing = allFiles.find(f => f.path === p);
  if (!existing) continue;
  let fc = existing.content;
  let applied = 0;
  for (const edit of fileEdits) {
    if (fc.includes(edit.search)) { fc = fc.replace(edit.search, edit.replace); applied++; }
    else {
      const st = edit.search.split('\n').map(l => l.trim()).join('\n');
      const cl = fc.split('\n');
      for (let i = 0; i <= cl.length - edit.search.split('\n').length; i++) {
        if (cl.slice(i, i + edit.search.split('\n').length).map(l => l.trim()).join('\n') === st) {
          cl.splice(i, edit.search.split('\n').length, ...edit.replace.split('\n'));
          fc = cl.join('\n'); applied++; break;
        }
      }
    }
  }
  if (applied > 0) { seen.add(p); files.push({ path: p, content: fc }); }
}

