// ── SIZE SAFETY CHECK: reject files that shrunk by >50% (prevents destructive rewrites) ──
const safeFiles = [];
for (const file of files) {
  const existing = allFiles.find(f => f.path === file.path);
  if (existing && existing.content) {
    const ratio = file.content.length / existing.content.length;
    if (ratio < 0.5) {
      console.log('SAFETY: Rejected ' + file.path + ' — output is ' + Math.round(ratio * 100) + '% of original size (' + file.content.length + ' vs ' + existing.content.length + ')');
      continue;
    }
  }
  safeFiles.push(file);
}
files.length = 0;
files.push(...safeFiles);

return [{ json: { project_id: projectId, files } }];

