import StatsGrid from './components/StatsGrid'
import ForecastRow from './components/ForecastRow'
import RadarMap from './components/RadarMap'
import SettingsMenu from './components/SettingsMenu'
import LocationPicker from './components/LocationPicker'

// Services & Types
import { 
  fetchCurrentWeather, 
  fetchForecast, 
  geocodeLocation, 
  CurrentWeather, 
  ForecastDay,
  getFallbackWeather,
  getFallbackForecast,
  LocationResult
} from './lib/weatherService'

type ViewType = 'home' | 'locations' | 'settings';

function WeatherApp() {
  const [isDark] = useDarkMode()

  // Navigation State
  const [activeTab, setActiveTab] = useState<ViewType>('home')

  // Location Context from Hook
  const { 
    currentLocation, 
    savedLocations, 
    addLocation, 
    removeLocation,
    updateCurrentLocation 
  } = useLocation()

  const [weatherData, setWeatherData] = useState<CurrentWeather | null>(null)
  const [forecastData, setForecastData] = useState<ForecastDay[]>([])

  const [loading, setLoading] = useState<boolean>(true)
  const [error, setError] = useState<string | null>(null)

  // Fetch Logic
  const fetchWeatherData = async (lat: number, lon: number) => {
    try {
      setLoading(true)
      setError(null)

      const [current, forecast] = await Promise.all([
        fetchCurrentWeather(lat, lon),
        fetchForecast(lat, lon)
      ])

      setWeatherData(current)
      setForecastData(forecast)
    } catch (err) {
      console.error('Failed to fetch weather data:', err)
      setError('Unable to connect to satellite uplink')
      // Fallback to mock data on API failure
      const mockWeather = getFallbackWeather()
      const mockForecast = getFallbackForecast()
      setWeatherData(mockWeather)
      setForecastData(mockForecast)
    } finally {
      setLoading(false)
    }
  }

  // Trigger weather fetch when location changes
  useEffect(() => {
    if (currentLocation && currentLat !== currentLocation.lat || currentLon !== currentLocation.lon) {
      const { lat, lon } = currentLocation
      fetchWeatherData(lat, lon)
    }
  }, [currentLocation])

  // Initial Load - Check for saved location
  useEffect(() => {
    if (savedLocations.length > 0 && !weatherData) {
      // Use first saved location or current location from context
      const initialLoc = currentLocation || savedLocations[0]
      fetchWeatherData(initialLoc.lat, initialLoc.lon)
    } else if (!currentLocation && !weatherData) {
      // No saved location - show LocationPicker by default
      setActiveTab('locations')
    }
  }, [])

  // Search Handler (Triggered by Header or LocationPicker)
  const handleSearch = async (query: string | LocationResult) => {
    try {
      setLoading(true)
      setError(null)

      let location: LocationResult;

      if (typeof query === 'string') {
        // If passed a string, geocode it first
        location = await geocodeLocation(query);
      } else {
        // If passed an object directly from picker
        location = query;
      }

      updateCurrentLocation(location)

      await fetchWeatherData(location.lat, location.lon)

      // Add to saved locations if not already there
      const exists = savedLocations.some(l => l.name === location.name && l.lat === location.lat)
      if (!exists) {
        addLocation(location)
      }

      // If we were in locations view and selected a city, go back to home
      if (activeTab === 'locations') {
        setActiveTab('home');
      }
    } catch (err) {
      setError('Location not found in database')
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  // Get current location values for state management
  const currentLat = currentLocation?.lat || 35.6762
  const currentLon = currentLocation?.lon || 139.6503
  const cityName = currentLocation ? `${currentLocation.name}, ${currentLocation.country || ''}`.trim() : 'Neo-Tokyo Sector 7'

  // Background Gradient Logic - Defaulting to Midnight since we removed state access from here
  const getBackgroundGradient = () => 'from-indigo-950 via-purple-950 to-black'

  const accentColor = '#a78bfa';

  // View Renderers
  const renderHomeView = () => (
    <motion.div 
      key="home"
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -20 }}
      transition={{ duration: 0.3 }}
      className="w-full flex flex-col gap-6 pb-8"
    >
      <WeatherHero weather={weatherData} loading={loading} />
      <StatsGrid weather={weatherData} loading={loading} />
      <ForecastRow forecast={forecastData} loading={loading} />
      <RadarMap />
    </motion.div>
  )

  const renderSettingsView = () => (
     <motion.div 
        key="settings"
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        exit={{ opacity: 0, scale: 0.95 }}
        transition={{ duration: 0.3 }}
        className="w-full flex flex-col gap-6 pb-8"
     >
       <SettingsMenu />
    </motion.div>
  )

  const renderLocationsView = () => (
      // This is now a full screen view when activeTab === 'locations'
      <div className="hidden"> 
        {/* Handled by LocationPicker overlay logic below */}
      </div>
  )

  return (
    <div className={`flex flex-col h-screen w-full overflow-hidden relative z-0 ${getBackgroundGradient()}`}>
      {/* Ambient Glow Effects */}
      <motion.div
        animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.5, 0.3] }}
        transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
        className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] rounded-full blur-[120px] pointer-events-none z-0"
        style={{ backgroundColor: `${accentColor}1a` }}
      />

      {/* Fixed Header */}
      <Header 
        onSearch={handleSearch} 
        loading={loading}
        error={error}
        currentTab={activeTab} // Reusing prop name for compatibility, but logic uses view state
        setTab={(tab) => {
          if (tab === 'settings') setActiveTab('settings');
          else setActiveTab('locations'); // Open picker on search/header interaction
        }}
      />

      {/* Location Picker Overlay / Screen */}
      <LocationPicker 
        isOpen={activeTab === 'locations'} 
        onClose={() => {
           if (activeTab === 'locations') setActiveTab('home');
        }} 
        onSelectLocation={handleSearch}
      />

      {/* Main Content Area */}
      <main className="flex-1 flex items-center justify-center px-4 pt-[72px] pb-[80px] overflow-y-auto scrollbar-hide">
        <div className="w-full max-w-lg relative z-10 min-h-[calc(100vh-152px)] flex items-center justify-center">
          {error && activeTab !== 'settings' && (
            <motion.div 
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className="w-full bg-red-500/20 border border-red-500/30 text-red-200 p-3 rounded-lg text-sm text-center mb-4"
            >
              {error}
            </motion.div>
          )}

          {/* Loading Spinner */}
          {loading && (
            <motion.div
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              className="absolute inset-0 flex items-center justify-center bg-slate-950/80 backdrop-blur-sm z-20"
            >
              <div className="flex flex-col items-center gap-4">
                {/* Animated Spinner */}
                <motion.div
                  animate={{ rotate: 360 }}
                  transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                  className="w-16 h-16 border-4 border-primary/20 border-t-primary rounded-full shadow-[0_0_30px_rgba(107,254,156,0.3)]"
                />
                <motion.p 
                  animate={{ opacity: [0.5, 1, 0.5] }}
                  transition={{ duration: 1.5, repeat: Infinity }}
                  className="text-primary font-medium tracking-wider text-sm uppercase"
                >
                  Initializing...
                </motion.p>
              </div>
            </motion.div>
          )}

          <AnimatePresence mode="wait">
             {activeTab === 'home' && renderHomeView()}
             {activeTab === 'settings' && renderSettingsView()}
             {/* Locations view is handled by the overlay modal logic above */}
          </AnimatePresence>
        </div>
      </main>

      {/* Fixed Bottom Navigation */}
      <BottomNav 
        activeTab={activeTab}
        onNavigate={(view) => {
          setActiveTab(view);
        }} 
      />
    </div>
  )
}

function App() {
  return (
    <SettingsProvider>
      <WeatherApp />
    </SettingsProvider>
  )
}

export default App

import React from 'react';
import { motion } from 'framer-motion'
import { Home, CloudSun, Map, Settings } from 'lucide-react' 

type ViewType = 'home' | 'forecast' | 'radar' | 'settings';

interface BottomNavProps {
  activeTab: ViewType;
  onNavigate: (view: ViewType) => void;
}

const navItems: { id: ViewType; icon: React.ReactNode; label: string }[] = [
  { id: 'home', icon: <Home size={24} />, label: 'Home' },
  { id: 'forecast', icon: <CloudSun size={24} />, label: 'Forecast' },
  { id: 'radar', icon: <Map size={24} />, label: 'Radar' },
  { id: 'settings', icon: <Settings size={24} />, label: 'Settings' },
];

export default function BottomNav({ activeTab, onNavigate }: BottomNavProps) {
  return (
    <motion.div
      initial={{ y: 100 }}
      animate={{ y: 0 }}
      className="fixed bottom-0 left-0 right-0 z-50 h-[72px] bg-gradient-to-t from-black/95 to-black/80 backdrop-blur-md border-t border-white/5 flex items-center justify-center shadow-[0_-10px_40px_rgba(0,0,0,0.6)]"
    >
      <div className="flex gap-2 px-4 py-3 bg-transparent w-full max-w-sm justify-around">
