            className={`relative flex items-center justify-center w-14 h-14 rounded-xl transition-all duration-300 group ${
              activeTab === item.id 
                ? 'text-amber-400 bg-amber-400/20 shadow-[0_0_15px_rgba(251,191,36,0.3)]' 
                : 'text-gray-500 hover:text-gray-300 hover:bg-white/5'
            }`}
          >
             {React.cloneElement(item.icon as React.ReactElement, { 
               className: `relative z-10 transition-all duration-300 ${activeTab === item.id ? 'drop-shadow-[0_0_8px_rgba(251,191,36,0.6)]' : ''}`
             })}
          </motion.button>
        ))}
      </div>
    </motion.div>
  )
}

import React from 'react'
import { motion, useInView } from 'framer-motion'
import { Sun, Cloud, CloudRain, Wind, Droplets, Zap, Moon, CloudMoon, Snowflake } from 'lucide-react'
import { ForecastDay, getWeatherIconClass, formatTemperature } from '../lib/weatherService'
import { useSettings } from '../context/SettingsContext'

interface ForecastRowProps {
  forecast: ForecastDay[];
  loading: boolean;
}

const getIcon = (iconType: string) => {
  if (iconType === 'sun') return <Sun className="w-6 h-6 text-yellow-400 drop-shadow-[0_0_5px_rgba(250,204,21,0.5)]" />
  if (iconType === 'cloudy' || iconType === 'fog') return <Cloud className="w-6 h-6 text-gray-300" />
  if (iconType === 'rain' || iconType === 'showers') return <Droplets className="w-6 h-6 text-blue-400 drop-shadow-[0_0_5px_rgba(96,165,250,0.5)]" />
  if (iconType === 'wind' || iconType === 'gust') return <Wind className="w-6 h-6 text-cyan-300" />
  if (iconType === 'storm') return <Zap className="w-6 h-6 text-yellow-500 drop-shadow-[0_0_5px_rgba(234,179,8,0.5)]" />
  if (iconType === 'snow') return <Snowflake className="w-6 h-6 text-blue-200" />
  // Night variants could be added here
  return <Sun className="w-6 h-6 text-cyan-400" />
}

export default function ForecastRow({ forecast, loading }: ForecastRowProps) {
  const containerRef = React.useRef<HTMLDivElement>(null)
  const isInView = useInView(containerRef, { once: true, amount: 0.3 })
  const { settings } = useSettings()

  if (loading && forecast.length === 0) {
     return (
       <div className="w-full max-w-md mx-auto px-4 mb-6">
         <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wide mb-4 ml-1 flex items-center gap-2">
           Atmospheric Timeline
           <span className="px-2 py-0.5 rounded bg-primary/20 border border-primary/30 text-xs text-primary animate-pulse">LOADING</span>
         </h3>
         <div className="w-full overflow-x-auto pb-6 scrollbar-hide px-1 flex gap-4 snap-x">
           {[1, 2, 3].map((i) => (
             <motion.div 
               key={i}
               animate={{ opacity: [0.5, 0.8, 0.5] }}
               transition={{ duration: 1.5, repeat: Infinity, delay: i * 0.2 }}
               className="snap-start glass-card min-w-[300px] h-[60px] flex items-center justify-between px-5 rounded-xl border border-white/10 bg-surface-dark/50 backdrop-blur-sm"
             >
                <div className="w-20 h-5 bg-gray-700/50 rounded animate-pulse shrink-0"></div>
                <div className="w-8 h-8 rounded-full bg-gray-700/50 flex-shrink-0"></div>
                <div className="w-24 h-5 bg-gray-700/50 rounded animate-pulse shrink-0 text-right"></div>
             </motion.div>
           ))}
         </div>
       </div>
     )
  }

  return (
    <div className="w-full max-w-md mx-auto px-4 mb-6" ref={containerRef}>
      <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wide mb-4 ml-1 flex items-center gap-2">
        Forecast Timeline
        <span className="px-2 py-0.5 rounded bg-primary/20 border border-primary/30 text-xs text-primary animate-pulse">LIVE</span>
      </h3>

      {/* Horizontal Scroll Container */}
      <div className="w-full overflow-x-auto pb-6 scrollbar-hide px-1 flex gap-4 snap-x">
        {forecast.map((day, index) => (
          <motion.div
            key={index}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.4, delay: index * 0.1, ease: "easeOut" }}
            className="snap-start glass-card min-w-[300px] h-[60px] flex items-center justify-between px-5 rounded-xl border border-white/5 bg-surface-dark/50 backdrop-blur-sm shadow-lg relative overflow-hidden group hover:border-primary/30 transition-colors"
          >
            {/* Date Left - Bold text-lg */}
            <div className="text-lg font-bold text-gray-100 shrink-0">
              {day.date === 'Today' ? 'Today' : day.date.split(' ')[0]} 
            </div>

            {/* Weather Icon Center */}
            <div className="flex-shrink-0 drop-shadow-md mx-auto">
               {getIcon(getWeatherIconClass(day.weatherCode))}
            </div>

            {/* Temps Right - Amber High / Blue-Gray Low */}
            <div className="text-right shrink-0 flex items-center gap-2">
              <span className="text-lg font-semibold text-amber-400 tabular-nums drop-shadow-[0_0_8px_rgba(251,191,36,0.3)]">
                {formatTemperature(day.high, settings.tempUnit)}
              </span>
              <span className="text-sm text-slate-500 tabular-nums opacity-70">/</span>
              <span className="text-lg font-semibold text-slate-400 tabular-nums">
                {formatTemperature(day.low, settings.tempUnit)}
              </span>
            </div>
          </motion.div>
        ))}
      </div>

    </div>
  )
}

import React, { useState } from 'react'
import { motion } from 'framer-motion'
import { Menu, Settings, ChevronDown, MapPin } from 'lucide-react'
import { useLocation } from '../hooks/useLocation'
import LocationPicker from './LocationPicker'

interface HeaderProps {
  onSearch: (query: string) => Promise<void>; 
  loading: boolean;
  error: string | null;
  currentTab: string;
  setTab: (tab: string) => void;
}

export default function Header({ onSearch, loading, error, currentTab, setTab }: HeaderProps) {

  const [isPickerOpen, setIsPickerOpen] = useState(false)

  // Get city name from Location context
  const { currentLocation } = useLocation()
  const cityName = currentLocation ? `${currentLocation.name}, ${currentLocation.country || ''}`.trim() : 'Atmospheric'

  return (
    <>
      {/* Top Navigation Bar - Dark Blue Surface (#040f38) */}
      <header className="h-[64px] fixed top-0 left-0 right-0 z-50 flex items-center justify-between px-4 py-3 bg-surface-dark-blue/90 backdrop-blur-md border-b border-white/10 shadow-lg">

        {/* Hamburger Menu - Left */}
        <motion.button 
          whileTap={{ scale: 0.9 }}
          className="p-2 rounded-lg hover:bg-white/5 transition-all duration-200"
          ariaLabel="Menu"
        >
          <Menu size={16} className="text-primary stroke-[2px]" />
        </motion.button>

        {/* Location Indicator - Center */}
        <div 
          onClick={() => setIsPickerOpen(true)}
          className="flex items-center gap-2 cursor-pointer group"
        >
          <MapPin size={14} className="text-primary shrink-0 drop-shadow-[0_0_8px_rgba(107,254,156,0.5)]" />
          <span className="text-lg font-semibold text-white tracking-wide drop-shadow-sm">
            {cityName || "Atmospheric"}
          </span>
          <ChevronDown size={16} className="text-primary transition-transform duration-300 group-hover:rotate-180" />
        </div>

        {/* Settings Button - Right */}
        <motion.button 
          whileTap={{ scale: 0.9 }}
          onClick={() => setTab('settings')} 
          className="p-2 rounded-lg hover:bg-white/5 transition-all duration-200 relative"
          ariaLabel="Settings"
        >
          <div className={`absolute inset-0 bg-primary blur-md opacity-0 group-hover:opacity-40 transition-opacity rounded-full ${currentTab === 'settings' ? 'opacity-60' : ''}`} />
          <Settings size={16} className={`relative stroke-[2px] ${currentTab === 'settings' ? 'text-white drop-shadow-glow-green' : 'text-primary'}`} />
        </motion.button>

      </header>

      {/* Location Picker Modal */}
      <LocationPicker 
        isOpen={isPickerOpen} 
        onClose={() => setIsPickerOpen(false)} 
        onSelectLocation={async (loc) => {
           await onSearch(loc.name);
        }}
      />
    </>
  )
}

import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion'
import { Search, X, MapPin, Plus, ChevronRight } from 'lucide-react'
import { geocodeLocation, LocationResult } from '../lib/weatherService'

interface LocationPickerProps {
  isOpen: boolean;
  onClose?: () => void; // For overlay mode
  onSelectLocation: (location: LocationResult) => Promise<void>;
  currentLocation?: LocationResult | null;
}

// Mock Data for Demo if API fails or to populate list initially
const MOCK_LOCATIONS = [
  { name: 'Neo-Tokyo', country: 'JP', lat: 35.6762, lon: 139.6503 },
  { name: 'San Francisco', country: 'US', lat: 37.7749, lon: -122.4194 },
  { name: 'London', country: 'UK', lat: 51.5074, lon: -0.1278 },
  { name: 'Berlin', country: 'DE', lat: 52.5200, lon: 13.4050 },
];

export default function LocationPicker({ isOpen, onClose, onSelectLocation }: LocationPickerProps) {
  const [query, setQuery] = useState('')
  // Use a ref to store results so we don't lose them if state updates trigger re-renders unexpectedly during search
  const [results, setResults] = useState<LocationResult[]>([])
  const [loading, setLoading] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    // Initial population with mock data (simulating "Saved Locations" or "Popular")
    if (!query && results.length === 0) {
       setResults(MOCK_LOCATIONS as unknown as LocationResult[])
    }

    if (isOpen && inputRef.current) {
      setTimeout(() => inputRef.current?.focus(), 100)
    }
  }, [isOpen, query])

  const handleSearch = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value
    setQuery(val)

    if (!val.trim()) {
      // Reset to mock data on clear
       setResults(MOCK_LOCATIONS as unknown as LocationResult[])
      return
    }

    setLoading(true)
    try {
      // Simulate network delay for effect
      await new Promise(resolve => setTimeout(resolve, 600)) 

      const data = await geocodeLocation(val)
      setResults([data]) 
    } catch (err) {
      console.error("Search failed", err)
      setResults([])
    } finally {
      setLoading(false)
    }
  }

  const handleSelect = async (loc: LocationResult) => {
    await onSelectLocation(loc)
    if(onClose) onClose(); // If overlay, close it. If screen view, App handles routing.
    setQuery('')
  }

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop - Only show if this is an overlay */}
          {onClose && (
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={onClose}
              className="fixed inset-0 z-[60] bg-black/80 backdrop-blur-sm"
            />
          )}

          {/* Main Container */}
          <motion.div 
             // If overlay, slide up from bottom. If full screen view (no onClose), just fade in.
            initial={{ y: onClose ? '100%' : 0, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: onClose ? '100%' : 0, opacity: 0 }}
            transition={{ type: "spring", damping: 25, stiffness: 300, duration: 0.4 }}
            className={`fixed inset-0 z-[70] bg-slate-950/95 backdrop-blur-xl border-t border-white/10 shadow-[0_-10px_40px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col ${!onClose ? 'relative' : ''}`}
          >
            {/* Header */}
            <div className="p-6 pb-2 pt-12 bg-slate-950/50 backdrop-blur-xl z-10 sticky top-0">
              <h2 className="text-3xl font-bold text-white mb-1 uppercase tracking-wide drop-shadow-[0_0_10px_rgba(168,85,247,0.4)]">Manage Locations</h2>
              <p className="text-sm text-gray-400">Find a city or airport code to track weather</p>
            </div>

            {/* Search Input */}
            <div className="px-6 py-4 relative z-10 w-full max-w-lg mx-auto shadow-lg bg-slate-950/80 backdrop-blur-md border-b border-white/5">
               <div className="relative group">
                 <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                 <input 
                   ref={inputRef}
                   type="text" 
                   placeholder="Search for a city or airport..."
                   value={query}
                   onChange={handleSearch}
                   className="w-full bg-slate-900/80 border border-white/10 rounded-xl outline-none text-lg font-medium text-white px-4 py-3 pl-12 placeholder-gray-500 focus:border-purple-500 focus:ring-1 focus:ring-purple-500 transition-all shadow-inner"
                 />
                 {query && (
                   <button 
                     onClick={() => setQuery('')}
                     className="absolute right-3 top-1/2 -translate-y-1/2 p-1 text-gray-400 hover:text-purple-400 transition-colors rounded-full hover:bg-white/5"
                   >
                     <X size={18} />
                   </button>
                 )}
               </div>
            </div>

            {/* Results List */}
            <div className="flex-1 overflow-y-auto px-6 pt-4 pb-20 scrollbar-hide w-full max-w-lg mx-auto">
              {loading && (
                <div className="py-8 text-center flex items-center justify-center gap-3 animate-pulse">
                  <Search size={20} className="text-purple-500" /> 
                  <span className="text-purple-300 font-medium tracking-wide">Scanning Satellite...</span>
                </div>
              )}

              {!loading && results.length > 0 && (
                 <motion.div 
                   initial={{ opacity: 0, y: 20 }}
                   animate={{ opacity: 1, y: 0 }}
                   className="space-y-3"
                 >
                    {results.map((loc) => (
                      <button
                        key={`${loc.name}-${loc.lat}`}
                        onClick={() => handleSelect(loc)}
                        className="w-full h-[72px] flex items-center justify-between p-4 rounded-xl bg-slate-900/50 border border-white/5 hover:bg-purple-900/10 hover:border-purple-500/30 transition-all group relative overflow-hidden"
                      >
                        <div className="absolute inset-y-0 left-0 w-[2px] bg-gradient-to-b from-purple-500 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />

                         <div className="flex items-center gap-4">
                           <MapPin className="w-6 h-6 text-purple-400/80 group-hover:text-purple-400 drop-shadow-[0_0_5px_rgba(168,85,247,0.4)]" />
                           <div className="text-left">
                             <h3 className="font-bold text-white text-lg leading-tight">{loc.name}</h3>
                             <p className="text-sm text-gray-400 mt-1 uppercase tracking-wide font-semibold">{loc.country || 'UNK'}</p>
                           </div>
                         </div>

                         {/* Add Icon or Chevron */}
