// --- API Functions (OpenWeatherMap + Mock Fallback) ---

export async function fetchCurrentWeather(lat: number, lon: number): Promise<CurrentWeather> {
  // Simulate network delay for consistency in UI loading states
  await new Promise(resolve => setTimeout(resolve, 400));

  if (!WEATHER_API_KEY) {
    console.log('No API key provided. Using mock data.');
    return MOCK_CURRENT;
  }

  try {
    const url = `https://api.openweathermap.org/data/2.5/weather?lat=${lat}&lon=${lon}&appid=${WEATHER_API_KEY}&units=metric`;
    const response = await fetch(url);

    if (!response.ok) {
      throw new Error(`Weather API error: ${response.status}`);
    }

    const data: any = await response.json();

    return {
      temperature: Math.round(data.main.temp),
      humidity: data.main.humidity,
      windSpeed: Math.round(data.wind.speed * 3.6), // Convert m/s to km/h for consistency with mock
      precipitation: (data.rain?.['1h'] || 0),
      condition: data.weather[0].description.charAt(0).toUpperCase() + data.weather[0].description.slice(1),
      iconCode: data.weather[0].id, // OpenWeatherMap IDs are compatible enough for our mapping logic
      location: data.name,
      high: Math.round(data.main.temp_max),
      low: Math.round(data.main.temp_min),
      pressure: data.main.pressure,
      visibility: Math.floor(data.visibility / 1000), // Convert meters to km
      uvIndex: data.uvi || 0,
      dewPoint: Math.round(data.main.dew_point)
    };
  } catch (error) {
    console.error('Failed to fetch current weather:', error);
    return MOCK_CURRENT;
  }
}

export async function fetchForecast(lat: number, lon: number): Promise<ForecastDay[]> {
  // Simulate network delay
  await new Promise(resolve => setTimeout(resolve, 400));

  if (!WEATHER_API_KEY) {
    console.log('No API key provided. Using mock forecast.');
    return MOCK_FORECAST;
  }

  try {
    const url = `https://api.openweathermap.org/data/2.5/forecast?lat=${lat}&lon=${lon}&appid=${WEATHER_API_KEY}&units=metric`;
    const response = await fetch(url);

    if (!response.ok) {
      throw new Error(`Forecast API error: ${response.status}`);
    }

    const data: any = await response.json();

    // Aggregate 3-hour forecasts into daily summaries
    const groupedByDate = data.list.reduce((acc: any, item: any) => {
      const dateKey = new Date(item.dt * 1000).toISOString().split('T')[0];
      if (!acc[dateKey]) {
        acc[dateKey] = [];
      }
      acc[dateKey].push(item);
      return acc;
    }, {});

    const result: ForecastDay[] = Object.entries(groupedByDate)
      .slice(0, 7) // Limit to next 7 days
      .map(([dateStr, items]: [string, any]) => {
        const maxTemp = Math.max(...items.map((i: any) => i.main.temp_max));
        const minTemp = Math.min(...items.map((i: any) => i.main.temp_min));
        // Use the weather code from noon-ish or just the first one
        const weatherCode = items[0].weather[0].id;

        // Format date to "Today", "Tue", etc. similar to mock data if needed, 
        // but for now returning standard weekday short name works well with components expecting strings
        const dateObj = new Date(dateStr);
        const today = new Date();
        let label = dateObj.toLocaleDateString('en-US', { weekday: 'short' });

        // Adjust "Today" logic if the forecast includes current day
        if (dateStr === today.toISOString().split('T')[0]) {
          label = 'Today';
        }

        return {
          date: label,
          high: Math.round(maxTemp),
          low: Math.round(minTemp),
          weatherCode: weatherCode
        };
      });

    return result;
  } catch (error) {
    console.error('Failed to fetch forecast:', error);
    return MOCK_FORECAST;
  }
}

// Geocoding Logic (OpenWeatherMap + Mock Fallback)
export async function geocodeLocation(query: string): Promise<LocationResult> {
  // Simulate network delay slightly for UI consistency
  await new Promise(resolve => setTimeout(resolve, 300));

  if (!query.trim()) throw new Error('Query required');

  const lowerQuery = query.toLowerCase();

  // --- Mock Fallback Data (Active when no API key or search fails) ---
  const mockLocations: Record<string, LocationResult> = {
    'tokyo': { name: 'Tokyo', lat: 35.6762, lon: 139.6503, country: 'Japan' },
    'new york': { name: 'New York', lat: 40.7128, lon: -74.0060, country: 'USA' },
    'london': { name: 'London', lat: 51.5074, lon: -0.1278, country: 'UK' },
    'paris': { name: 'Paris', lat: 48.8566, lon: 2.3522, country: 'France' },
    'sydney': { name: 'Sydney', lat: -33.8688, lon: 151.2093, country: 'Australia' }
  };

  // If no API key exists, use mock logic immediately
  if (!WEATHER_API_KEY) {
    let result = Object.values(mockLocations).find(loc => loc.name.toLowerCase() === lowerQuery);
    if (!result) {
      console.warn(`Location '${query}' not found in mock DB. Returning Tokyo.`);
      result = mockLocations['tokyo'];
    }
    return result;
  }

  // Try Real API
  try {
    const url = `https://api.openweathermap.org/geo/1.0/direct?q=${encodeURIComponent(query)}&limit=5&appid=${WEATHER_API_KEY}`;
    const response = await fetch(url);

    if (!response.ok) throw new Error('Geocoding API failed');

    const data: any[] = await response.json();

    if (data && data.length > 0) {
      return {
        name: data[0].name,
        lat: parseFloat(data[0].lat),
        lon: parseFloat(data[0].lon),
        country: data[0].country || undefined
      };
    }

    // If API returns empty array (location not found)
    throw new Error('Location not found');

  } catch (error) {
    console.warn(`Geocoding failed for '${query}', falling back to mock or default:`, error);

    // Fallback to mock logic if real API fails
    let result = Object.values(mockLocations).find(loc => loc.name.toLowerCase() === lowerQuery);
    if (!result) {
      console.warn(`Location '${query}' not found in fallback DB. Returning Tokyo.`);
      result = mockLocations['tokyo'];
    }
    return result;
  }
}

