// Ensures TemperatureUnit parameter uses 'celsius' | 'fahrenheit' not 'C'/'F'
export function formatTemperature(temp: number, unit: 'celsius' | 'fahrenheit'): string {
  if (unit === 'fahrenheit') {
    const f = Math.round((temp * 9/5) + 32);
    return `${f}°F`;
  }
  return `${Math.round(temp)}°C`;
}

export function getWeatherIconClass(code: number): string {
  // Open-Meteo WMO codes mapping to simple strings for icons
  if (code === 0) return 'sun';
  if (code >= 1 && code <= 3) return 'cloudy';
  if (code >= 45 && code <= 48) return 'fog';
  if (code >= 51 && code <= 67) return 'rain';
  if (code >= 71 && code <= 77) return 'snow';
  if (code >= 95) return 'storm';
  if (code >= 80 && code <= 82) return 'showers';
  return 'sun'; // Default
}

// Fixed function to return human-readable weather condition from WMO code
export function getWeatherCondition(code: number): string {
  if (code === 0) return 'Clear';
  if (code >= 1 && code <= 3) return 'Partly Cloudy';
  if (code >= 45 && code <= 48) return 'Fog';
  if (code >= 51 && code <= 67) return 'Rain';
  if (code >= 71 && code <= 77) return 'Snow';
  if (code >= 80 && code <= 82) return 'Showers';
  if (code >= 95 && code <= 99) return 'Thunderstorm';
  return 'Unknown'; // Fallback for unmapped codes
}

