import { useState, useEffect } from 'react';
import { LocationResult } from '../lib/weatherService';

const STORAGE_KEY = 'weather-app-location';

interface LocationData extends LocationResult {
  zipCode?: string;
}

export function useLocation() {
  const [currentLocation, setCurrentLocation] = useState<LocationResult | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadFromStorage();
  }, []);

  const loadFromStorage = () => {
    try {
      const stored = localStorage.getItem(STORAGE_KEY);
      if (stored) {
        const data: LocationData = JSON.parse(stored);
        setCurrentLocation({
          name: data.name,
          lat: data.lat,
          lon: data.lon,
          country: data.country
        });
      }
    } catch (error) {
      console.error('Failed to load location from storage:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const saveLocation = (location: LocationResult) => {
    try {
      const data: LocationData = {
        name: location.name,
        lat: location.lat,
        lon: location.lon,
        country: location.country || undefined
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
      setCurrentLocation(location);
    } catch (error) {
      console.error('Failed to save location:', error);
    }
  };

  const saveZipCode = (zipCode: string) => {
    try {
      const data: LocationData = {
        zipCode,
        name: `Zip Code ${zipCode}`,
        lat: 0,
        lon: 0
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
    } catch (error) {
      console.error('Failed to save zip code:', error);
    }
  };

  const saveCoordinates = (lat: number, lon: number, name?: string) => {
    try {
      const data: LocationData = {
        lat,
        lon,
        name: name || `Lat ${lat}, Lon ${lon}`,
        country: undefined
      };
      localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
      setCurrentLocation({ lat, lon, name: data.name });
    } catch (error) {
      console.error('Failed to save coordinates:', error);
    }
  };

  const clearLocation = () => {
    try {
      localStorage.removeItem(STORAGE_KEY);
      setCurrentLocation(null);
    } catch (error) {
      console.error('Failed to clear location:', error);
    }
  };

  return [currentLocation, saveLocation, isLoading] as const;
}

