const query = $json.query || {};
const body = $json.body || $json;
const message = query.message || body.message || body.goal || '';
const projectId = query.project_id || body.project_id || ('proj-' + Date.now());
const reference_url = query.reference_url || body.reference_url || null;
const image_data = body.image_data || null;
return [{ json: { message, project_id: projectId, operation: 'init', goal: message, reference_url, image_data } }];

// MODIFIED: Absorbs Research: Build Project Context
// Caches _allFileContents, _researchDocs, _projectFileList in static data
// so Phase 2 chunks don't need to re-fetch or re-compute.
const memory = $('Extract Input').first().json;
const message = $('Extract Input').first().json.message;
const allFiles = $json.files || [];
const staticData = $getWorkflowStaticData('global');

// Cache all file contents for Phase 2
// Reset execution-scoped static data from prior runs
staticData._buildAttempt = 0;
staticData._buildResult = {};
staticData._reviewResult = {};
staticData.p2Results = [];
staticData.allTasks = [];
staticData._pipelineReport = '';

// Extract project memory (if it exists) — pipeline-managed, not a code file
const memoryFile = allFiles.find(f => f.path === 'memory.md');
const projectMemory = memoryFile ? memoryFile.content : '';
staticData._projectMemory = projectMemory;

// Filter memory.md from file list so planner/coder can't modify it
const codeFiles = allFiles.filter(f => f.path !== 'memory.md');
staticData._allFileContents = codeFiles;

const fileList = codeFiles.map(f => f.path);

// ─── Deep API Surface Extraction ─────────────────────────────────────
// Step 1: Build import count map — how many files import each file
const importCountMap = {}; // path -> count of files that import it
const sourceFiles = codeFiles.filter(f => f.path.match(/\.(ts|tsx|js|jsx)$/) && !f.path.includes('node_modules'));

for (const f of sourceFiles) {
  const importMatches = (f.content || '').matchAll(/from\s+['"]([^'"]+)['"]/g);
  for (const m of importMatches) {
    let importPath = m[1];
    if (importPath.startsWith('@/')) {
      // Handle @/ alias → src/
      importPath = 'src/' + importPath.substring(2);
    } else if (!importPath.startsWith('.')) {
      continue; // Skip npm packages
    } else {
      // Resolve relative import
      const dir = f.path.replace(/\/[^\/]+$/, '');
      importPath = dir + '/' + importPath;
    }
    const segments = importPath.split('/');
    const resolved = [];
    for (const seg of segments) {
      if (seg === '..') resolved.pop();
      else if (seg !== '.') resolved.push(seg);
    }
    const resolvedBase = resolved.join('/');
    // Find matching file
    for (const candidate of sourceFiles) {
      if (candidate.path === f.path) continue;
      const cBase = candidate.path.replace(/\.(ts|tsx|js|jsx)$/, '');
      const cIndex = candidate.path.replace(/\/index\.(ts|tsx|js|jsx)$/, '');
      if (cBase === resolvedBase || candidate.path === resolvedBase || cIndex === resolvedBase) {
        importCountMap[candidate.path] = (importCountMap[candidate.path] || 0) + 1;
      }
    }
  }
}

// Step 2: Deep extraction helpers
function extractFullBlock(content, startIdx) {
  // From startIdx (pointing at '{'), extract until matching '}'
  let depth = 0;
  let i = startIdx;
  while (i < content.length) {
    if (content[i] === '{') depth++;
    else if (content[i] === '}') {
      depth--;
      if (depth === 0) return content.substring(startIdx, i + 1);
    }
    i++;
  }
  return content.substring(startIdx, Math.min(startIdx + 500, content.length));
}

function extractDeepSurface(f) {
  const content = f.content || '';
  const lines = content.split('\n');
  const sections = { types: [], exports: [] };

  // Find interfaces referenced by createContext<T>, React.FC<T>, or hook return types
  // These are the "contract" interfaces that consumers need to know about
  const referencedTypes = new Set();
  const ctxMatch = content.match(/createContext<(\w+)/);
  if (ctxMatch) referencedTypes.add(ctxMatch[1]);
  const fcMatches = content.matchAll(/React\.FC<(\w+)>/g);
  for (const m of fcMatches) referencedTypes.add(m[1]);
  // Also find interfaces ending in Props, Type, Context, State, Config
  const knownSuffixes = /(?:Props|Type|Context|State|Config)$/;

  // Extract exported AND contract-referenced interfaces with full body
  const interfaceRegex = /(?:export\s+)?(?:declare\s+)?interface\s+(\w+)/g;
  let match;
  while ((match = interfaceRegex.exec(content)) !== null) {
    const name = match[1];
    const isExported = content.substring(Math.max(0, match.index - 10), match.index).includes('export');
    // Include if: exported, or referenced by context/FC, or has known suffix
    if (!isExported && !referencedTypes.has(name) && !knownSuffixes.test(name)) continue;
    const braceIdx = content.indexOf('{', match.index);
    if (braceIdx !== -1 && braceIdx - match.index < 200) {
      const body = extractFullBlock(content, braceIdx);
      const trimmedBody = body.length > 400 ? body.substring(0, 400) + '\n  ...\n}' : body;
      sections.types.push('interface ' + name + ' ' + trimmedBody);
    }
  }

  // Extract exported type aliases
  const typeRegex = /export\s+(?:declare\s+)?type\s+(\w+)\s*=\s*([^;]+);/g;
  while ((match = typeRegex.exec(content)) !== null) {
    sections.types.push('type ' + match[1] + ' = ' + match[2].substring(0, 200));
  }

  // Extract function signatures with return types
  // export const foo = (params): ReturnType => ...
  const constFnRegex = /export\s+const\s+(\w+)\s*=\s*(?:async\s+)?\(([^)]*)\)\s*(?::\s*([\w<>\[\],\s|&{}]+?))?\s*=>/g;
  while ((match = constFnRegex.exec(content)) !== null) {
    const name = match[1];
    const params = match[2].substring(0, 150);
    const retType = match[3] ? ': ' + match[3].trim() : '';
    // Hook return shapes — for useXxx, try to find the return type
    if (name.startsWith('use')) {
      sections.exports.push(name + '(' + params + ')' + retType);
    } else {
      sections.exports.push(name + '(' + params + ')' + retType);
    }
  }

  // export function foo(params): ReturnType
  const fnDeclRegex = /export\s+(?:async\s+)?function\s+(\w+)\s*\(([^)]*)\)\s*(?::\s*([\w<>\[\],\s|&{}]+?))?[\s{]/g;
  while ((match = fnDeclRegex.exec(content)) !== null) {
    const name = match[1];
    const params = match[2].substring(0, 150);
    const retType = match[3] ? ': ' + match[3].trim() : '';
    sections.exports.push(name + '(' + params + ')' + retType);
  }

  // React component props — find React.FC<Props> or : React.FC<Props>
  const fcRegex = /export\s+(?:default\s+)?(?:const|function)\s+(\w+)[\s:]*(?:React\.)?FC<(\w+)>/g;
  while ((match = fcRegex.exec(content)) !== null) {
    sections.exports.push(match[1] + ': React.FC<' + match[2] + '>');
  }

  // export default component
  const defaultRegex = /export\s+default\s+(?:function\s+)?(\w+)/g;
  while ((match = defaultRegex.exec(content)) !== null) {
    // Avoid duplicates if already captured
    const name = match[1];
    if (!sections.exports.some(e => e.startsWith(name))) {
      sections.exports.push('default ' + name);
    }
  }

  // export { ... }
  const reExportRegex = /export\s+\{([^}]+)\}/g;
  while ((match = reExportRegex.exec(content)) !== null) {
    const names = match[1].split(',').map(n => n.trim().split(' as ')[0].trim()).filter(Boolean);
    for (const name of names) {
      if (!sections.exports.some(e => e.startsWith(name))) {
        sections.exports.push(name);
      }
    }
  }

  // Exported classes
  const classRegex = /export\s+(?:default\s+)?class\s+(\w+)(?:\s+extends\s+(\w+))?/g;
  while ((match = classRegex.exec(content)) !== null) {
    const ext = match[2] ? ' extends ' + match[2] : '';
    if (!sections.exports.some(e => e.includes(match[1]))) {
      sections.exports.push('class ' + match[1] + ext);
    }
  }

  // Exported enums
  const enumRegex = /export\s+(?:const\s+)?enum\s+(\w+)/g;
  while ((match = enumRegex.exec(content)) !== null) {
    const name = match[1];
    const braceIdx = content.indexOf('{', match.index);
    if (braceIdx !== -1) {
      const body = extractFullBlock(content, braceIdx);
      const trimmedBody = body.length > 200 ? body.substring(0, 200) + '\n  ...\n}' : body;
      sections.types.push('enum ' + name + ' ' + trimmedBody);
    }
  }

  return sections;
}

function extractShallowExports(f) {
  const lines = (f.content || '').split('\n');
  const exports = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (/^export\s+default\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').substring(0, 120));
    } else if (/^export\s+(const|let|var|function|class|interface|type|enum)\s/.test(trimmed)) {
      exports.push(trimmed.replace(/\{[\s\S]*$/, '{...}').replace(/=>[\s\S]*$/, '=> ...').substring(0, 150));
    } else if (/^export\s+\{/.test(trimmed)) {
      exports.push(trimmed.substring(0, 150));
    }
  }
  return exports;
}

// Step 3: Build API surface with import-count awareness
const apiSurface = [];
let apiSurfaceLen = 0;
const API_SURFACE_CAP = 6000;

// Sort files: most-imported first so they get deep treatment before cap
const sortedFiles = [...sourceFiles].sort((a, b) => {
  return (importCountMap[b.path] || 0) - (importCountMap[a.path] || 0);
});

for (const f of sortedFiles) {
  if (apiSurfaceLen >= API_SURFACE_CAP) break;
  const importCount = importCountMap[f.path] || 0;

  if (importCount >= 2) {
    // Deep surface for highly-imported files
    const deep = extractDeepSurface(f);
    if (deep.types.length === 0 && deep.exports.length === 0) continue;

    let block = '## ' + f.path + ' (imported by ' + importCount + ' files)\n';
    if (deep.types.length > 0) {
      block += '\n### Types\n' + deep.types.join('\n\n') + '\n';
    }
    if (deep.exports.length > 0) {
      block += '\n### Exports\n' + deep.exports.join('\n') + '\n';
    }

    // Respect cap — truncate block if needed
    const remaining = API_SURFACE_CAP - apiSurfaceLen;
    if (block.length > remaining) {
      block = block.substring(0, remaining - 20) + '\n... (truncated)';
    }
    apiSurface.push(block);
    apiSurfaceLen += block.length;
  } else {
    // Shallow surface for low-import files
    const exports = extractShallowExports(f);
    if (exports.length > 0) {
      const block = '## ' + f.path + '\n' + exports.join('\n');
      const remaining = API_SURFACE_CAP - apiSurfaceLen;
      if (block.length > remaining) break;
      apiSurface.push(block);
      apiSurfaceLen += block.length;
    }
  }
}

// Extract dependencies from package.json
let dependencies = {};
let devDependencies = {};
let depNames = [];
for (const f of allFiles) {
  if (f.path === 'package.json' || f.path.endsWith('/package.json')) {
    try {
      const pkg = JSON.parse(f.content);
      dependencies = { ...dependencies, ...(pkg.dependencies || {}) };
      devDependencies = { ...devDependencies, ...(pkg.devDependencies || {}) };
      depNames = [...Object.keys(pkg.dependencies || {}), ...Object.keys(pkg.devDependencies || {})];
    } catch(e) {}
  }
}

// Build research docs string
const depList = Object.entries(dependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
const devDepList = Object.entries(devDependencies).map(([k,v]) => `  ${k}: ${v}`).join('\n');
let researchDocs = '';
if (depList || devDepList) {
  researchDocs += '## Dependency Manifest\nOnly use packages listed here.\n';
  if (depList) researchDocs += `dependencies:\n${depList}\n`;
  if (devDepList) researchDocs += `devDependencies:\n${devDepList}\n`;
}
if (apiSurface.length > 0) {
  researchDocs += '\n## Project API Surface\nMatch these import/export signatures exactly when importing from project files.\n';
  researchDocs += apiSurface.join('\n\n');
}

// Cache for all downstream phases
staticData._researchDocs = researchDocs;
staticData._projectFileList = fileList;
staticData._projectApiSummary = apiSurface.join('\n');
staticData._projectDeps = depNames;

// Cache planner input in static data so Build Request can read it
// (Load Model HTTP response replaces $json, so downstream can't use $json)
staticData._plannerInput = {
  message,
  project_goal: memory.goal || message,
  project_id: memory.project_id,
  existing_files: fileList,
  api_summary: apiSurface.join('\n'),
  installed_packages: depNames,
  _scrapeData: memory._scrapeData || null,
  image_data: memory.image_data || null,
  project_memory: projectMemory
};

return [{ json: staticData._plannerInput }];

// Read planner input from static data (Load Model HTTP response replaces $json)
const staticData = $getWorkflowStaticData('global');
const plannerInput = staticData._plannerInput || {};
const message = plannerInput.message || '';
const existingFiles = plannerInput.existing_files || [];
const apiSummary = plannerInput.api_summary || '';
const installedPkgs = plannerInput.installed_packages || [];
const scrapeData = plannerInput._scrapeData;

let projectContext = '';
if (existingFiles.length > 0) {
  projectContext += `\
\
EXISTING PROJECT FILES (only reference files from this list):\
${existingFiles.join('\
')}\
`;
}
if (apiSummary) {
  projectContext += `\
API SURFACE (exports from each file):\
${apiSummary}\
`;
}
if (installedPkgs.length > 0) {
  projectContext += `\
INSTALLED PACKAGES (only reference packages from this list):\
${installedPkgs.join(', ')}\
`;
}

// Inject project memory for continuity across runs
const projectMemory = plannerInput.project_memory || '';
if (projectMemory) {
  projectContext += '\
\
PROJECT MEMORY (context from previous pipeline runs — use for continuity):\
' + projectMemory.substring(0, 4000) + '\
';
}

const plannerPrompt = `You are a Senior Software Architect and UI/UX Design Expert. Your job is to break a coding request into MULTIPLE structured tasks with detailed visual specifications.

DESIGN PRINCIPLES (apply to ALL task descriptions):
- Main interaction element must be centered and dominant (40-60% of viewport height)
- Use vertical single-column layouts for apps/games — never side-by-side grids unless explicitly requested
- Content hierarchy: hero/main action at top → stats/feedback → secondary actions (shop, settings) at bottom
- Mobile-first: everything fits in 100vh, no page-level scrollbars, internal scrolling only for lists
- Dark backgrounds with bright accent colors. Use gradients for depth (purple-900 to black, not flat colors)
- Every click/tap must produce visible feedback (scale animation, color flash, particle effect)
- Numbers should animate when they change (bounce, pulse, scale). Use tabular-nums for counters
- Cards: rounded-xl (12-16px), subtle shadows, semi-transparent backgrounds with backdrop-blur
- Buttons: press animation (scale 0.95), hover glow, disabled state with reduced opacity
- Color-code affordability: gold/amber = available, red/gray = locked, green = owned/success
- Typography: big bold numbers (text-4xl+), clear hierarchy via weight not just size
- Spacing: generous padding, never cramped. Mobile touch targets minimum 44px

WHEN A REFERENCE IMAGE IS PROVIDED:
- Describe the EXACT layout structure you see: column vs row, spacing ratios, component sizes
- Specify exact colors, gradients, border styles, and shadows visible in the image
- Note the visual hierarchy: what's biggest, what's brightest, what draws the eye first
- Describe animations or interactive states implied by the design (hover effects, active states)
- Include specific dimensions: "toilet button should be 150px diameter" not just "large button"
- The coder CANNOT see the image — your description is their ONLY reference Each task will be handled by a separate coder with 128K context who can write up to 6 files at once.\
\
Output a JSON object with ONE field:\
\
"tasks": array of task objects. IMPORTANT: You MUST create multiple tasks. Group files by concern (e.g. styles in one task, frontend components in another, config in another). Each task has:\
- task_id: string like "TASK-001"\
- description: detailed actionable description of what to implement, including specific requirements, color values, component names, API endpoints, and behavior. The coder cannot see the original request — your description is all they get.\
- files: array of exact file paths to create or modify. List EVERY file this task needs — the coder can ONLY write files listed here. For existing projects, prefer modifying files from the EXISTING PROJECT FILES list. For new projects or missing functionality, CREATE new file paths as needed.\
- dependencies: array of task_id strings this task depends on (empty if none)\
- complexity: "low", "medium", or "high"
- needs_concept: boolean — set to true if this task involves UI/visual work that has NO reference image from the user. Set to false if the user provided a reference image that covers this task's visual design, or if the task is purely logic/config with no visual component.\
\
RULES:\
- Always split work across multiple tasks by concern: styles, components, routes, config, etc.\
- Aim for 3-5 SMALL tasks. For tasks that modify existing files, each task should require no more than 3 SEARCH/REPLACE blocks. If a change needs more than 3 edits to one file, split it into separate tasks that each handle one concern. Only use full file content for NEW files that don't exist yet. CRITICAL: If a task creates a new component, that SAME task MUST also wire it into the parent that imports it. Never split component creation and component usage into separate tasks — the coder must write both files so the interface matches\
- SPLITTING RULE: If a task would touch more than 2 existing files, split it. TASK-001 updates the state/context, TASK-002 updates the components that consume it, TASK-003 wires them together.\
- The description must be SELF-CONTAINED — include ALL details the coder needs\
- For existing projects, reference files from the EXISTING PROJECT FILES list when modifying. You MAY create new files that do not exist yet.
- CRITICAL: For new projects (empty file list), you MUST include a setup task that creates: package.json (with ALL dependencies), index.html, vite.config.js (or next.config.js), tsconfig.json (if TypeScript), tailwind.config.js + postcss.config.js (if using Tailwind), and the main entry point (src/main.jsx or app/layout.tsx). The project MUST be buildable.\
- Detect the project type from the files and packages. If the project is a React/Vite frontend (no Express or backend framework in INSTALLED PACKAGES), focus all tasks on frontend files. Only create server/middleware/API handler tasks if Express or a similar backend framework is in INSTALLED PACKAGES.\
- In each task description, specify the EXACT import/export style each file should use (named vs default) based on the API SURFACE above.\
- NEVER create a task whose only purpose is deleting files. The coder cannot delete files — it can only create or modify. If dead files exist, ignore them. They do not affect the build.
- The FIRST task should always include project configuration files (package.json, config files, index.html) if they do not already exist. The project MUST compile and run after all tasks complete.
- NEVER include memory.md in any task's file list — it is managed by the pipeline
- Output ONLY the raw JSON object: {"tasks": [...]}\
- No markdown, no explanation — ONLY the JSON with tasks\
\
EXAMPLE — splitting a feature request for an existing React project:\
{\
  "tasks": [\
    {\
      "task_id": "TASK-001",\
      "description": "Add offline earnings state to GameContext: showOfflineEarnings boolean, offlineEarningsAmount number, dismissOfflineEarnings function. Add these to the context provider value object.",\
      "files": ["src/context/GameContext.tsx"],\
      "dependencies": [],\
      "complexity": "medium",\
      "needs_concept": false\
    },\
    {\
      "task_id": "TASK-002",\
      "description": "Create OfflineEarningsPopup component that shows earnings amount and has a dismiss button. Props: earnings (number), onClose (callback).",\
      "files": ["src/components/OfflineEarningsPopup.tsx"],\
      "dependencies": [],\
      "complexity": "low",\
      "needs_concept": false\
    },\
    {\
      "task_id": "TASK-003",\
      "description": "Wire OfflineEarningsPopup into GameScreen. Destructure showOfflineEarnings, offlineEarningsAmount, dismissOfflineEarnings from useGame(). Render popup conditionally when showOfflineEarnings is true.",\
      "files": ["src/components/GameScreen.tsx"],\
      "dependencies": ["TASK-001", "TASK-002"],\
      "complexity": "low",\
      "needs_concept": false\
    }\
  ]\
}`;

let messageContent;
if (scrapeData && scrapeData.screenshot_b64) {
  const cssTokensStr = JSON.stringify(scrapeData.css_tokens, null, 2);
  const domStr = scrapeData.dom_summary || '';
  messageContent = [
    { type: 'image_url', image_url: { url: `data:image/png;base64,${scrapeData.screenshot_b64}` } },
    { type: 'text', text: `${plannerPrompt}\
\
REFERENCE DESIGN (screenshot above):\
CSS Tokens:\
${cssTokensStr}\
\
DOM Structure:\
${domStr}\
\
Request: ${message}${projectContext}\
\
(Match the visual design, color palette, typography, and layout from the screenshot)` }
  ];
} else if (plannerInput.image_data) {
  const userImage = plannerInput.image_data;
  messageContent = [
    { type: 'image_url', image_url: { url: 'data:image/png;base64,' + userImage } },
    { type: 'text', text: plannerPrompt + '\
\
REFERENCE IMAGE (uploaded by user — replicate this design):\
\
Request: ' + message + projectContext }
  ];
} else {
  messageContent = `${plannerPrompt}\
\
Request: ${message}${projectContext}`;
}

return [{
  json: {
    model: $env.PLANNER_MODEL || 'qwen3.5-27b@q4_k_m',
    messages: [{ role: 'user', content: messageContent }],
    temperature: 1.0,
    top_p: 0.95,
    top_k: 20,
    min_p: 0.0,
    presence_penalty: 0.0,
    max_tokens: parseInt($env.PLANNER_MAX_TOKENS) || 32768,
    chat_template_kwargs: { enable_thinking: true, max_thinking_tokens: 4096 }
  }
}];

const raw = $json.choices[0].message.content || $json.choices[0].message.reasoning_content || '';
let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
content = content.replace(/<\/?task>/g, '').trim();
content = content.replace(/\n+(?:Reasoning|Note|Explanation):[\s\S]*/i, '').trim();
content = content.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let tasks, planDocument = '';
try {
  const parsed = JSON.parse(content);
  if (Array.isArray(parsed)) {
    tasks = parsed;
  } else {
    tasks = parsed.tasks || [parsed];
    planDocument = parsed.plan_document || '';
  }
} catch (e) {
  // Truncated JSON recovery: extract complete task objects
  const tasksMatch = content.match(/"tasks"\s*:\s*\[/);
  if (tasksMatch) {
    const arrStart = content.indexOf('[', tasksMatch.index);
    let bracketDepth = 0;
    let lastCompleteObj = -1;
    for (let i = arrStart; i < content.length; i++) {
      if (content[i] === '{') bracketDepth++;
      if (content[i] === '}') {
        bracketDepth--;
        if (bracketDepth === 0) lastCompleteObj = i;
      }
    }
    if (lastCompleteObj > arrStart) {
      const recoveredArr = content.substring(arrStart, lastCompleteObj + 1) + ']';
      try {
        tasks = JSON.parse(recoveredArr);
      } catch (e2) {
        tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
      }
    } else {
      tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
    }
  } else {
    tasks = [{ task_id: 'TASK-FALLBACK-' + Date.now(), description: content, files: [], dependencies: [], complexity: 'high' }];
  }
}

tasks = tasks.map(t => ({
  ...t,
  files: t.files || [],
  dependencies: t.dependencies || [],
  complexity: t.complexity || 'medium'
}));

return [{ json: { tasks, plan_document: planDocument } }];

// Research: Fetch library docs — Context7 → Exa fallback → Magic UI
const http = require('http');
const https = require('https');
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];
const tasks = $json.tasks || [];

// ─── 1. Extract libraries from package.json + task text ─────────────
const libs = new Set();
const pkgFile = allFiles.find(f => f.path === 'package.json');
if (pkgFile) {
  try {
    const pkg = JSON.parse(pkgFile.content);
    for (const dep of Object.keys(pkg.dependencies || {})) libs.add(dep);
    for (const dep of Object.keys(pkg.devDependencies || {})) libs.add(dep);
  } catch(e) {}
}
const taskText = tasks.map(t => t.description || '').join(' ').toLowerCase();
const knownLibs = ['react', 'next', 'nextjs', 'vite', 'tailwindcss', 'tailwind', 'express', 'prisma', 'framer-motion', 'heroui', 'zustand', 'zod', 'three', 'react-three', 'r3f', 'drei', '@react-three/fiber', '@react-three/drei'];
for (const lib of knownLibs) {
  if (taskText.includes(lib)) {
    const mapped = {'nextjs':'next','tailwind':'tailwindcss','react-three':'@react-three/fiber','r3f':'@react-three/fiber','drei':'@react-three/drei'};
    libs.add(mapped[lib] || lib);
  }
}
if (allFiles.some(f => f.path.match(/\.(jsx|tsx)$/))) libs.add('react');

// ─── 1.5. Scan source files for actual imports ─────────────────────
const actualImports = new Set();
for (const f of allFiles) {
  if (!f.path.match(/\.(ts|tsx|js|jsx)$/) || f.path.includes('node_modules')) continue;
  const content = f.content || '';
  // Match: import ... from 'package' or import 'package' (side-effect)
  const importMatches = content.matchAll(/(?:import\s+(?:[\s\S]*?\s+from\s+)?['"]([^'"./][^'"]*?)(?:\/[^'"]*)?['"]\s*;?|require\s*\(\s*['"]([^'"./][^'"]*?)(?:\/[^'"]*)?['"]\s*\))/g);
  for (const m of importMatches) {
    const pkg = m[1] || m[2];
    if (pkg) {
      // Handle scoped packages: @scope/name -> @scope/name
      if (pkg.startsWith('@')) {
        const parts = pkg.split('/');
        if (parts.length >= 2) actualImports.add(parts[0] + '/' + parts[1]);
      } else {
        actualImports.add(pkg);
      }
    }
  }
}

