// MODIFIED: Absorbs Split Into Chunks. Builds flat (task, chunk) queue.
// Queue is passed through data pipeline (not static data) to avoid stale reads after HTTP nodes.
const tasks = $json.tasks || [];
const planDocument = $json.plan_document || '';
const plannerInput = $('Prepare Planner Input').first().json;
const projectId = plannerInput.project_id;
const projectGoal = plannerInput.project_goal;

// Topological sort
const taskMap = new Map();
tasks.forEach(t => taskMap.set(t.task_id, t));
const inDegree = new Map();
const dependents = new Map();
tasks.forEach(t => {
  inDegree.set(t.task_id, 0);
  dependents.set(t.task_id, []);
});
tasks.forEach(t => {
  const deps = (t.dependencies || []).filter(d => taskMap.has(d));
  inDegree.set(t.task_id, deps.length);
  deps.forEach(d => dependents.get(d).push(t.task_id));
});
const topoQueue = [];
tasks.forEach(t => {
  if (inDegree.get(t.task_id) === 0) topoQueue.push(t.task_id);
});
const sorted = [];
while (topoQueue.length > 0) {
  const id = topoQueue.shift();
  sorted.push(taskMap.get(id));
  for (const dep of (dependents.get(id) || [])) {
    inDegree.set(dep, inDegree.get(dep) - 1);
    if (inDegree.get(dep) === 0) topoQueue.push(dep);
  }
}
if (sorted.length < tasks.length) {
  const sortedIds = new Set(sorted.map(t => t.task_id));
  tasks.forEach(t => { if (!sortedIds.has(t.task_id)) sorted.push(t); });
}

// Flatten into (task, chunk) queue — 2 files per chunk
const chunkSize = 15;
const queue = [];
for (const task of sorted) {
  const taskFiles = task.files || [];
  const chunks = [];
  for (let i = 0; i < taskFiles.length; i += chunkSize) {
    chunks.push(taskFiles.slice(i, i + chunkSize));
  }
  if (taskFiles.length === 0) continue;  // skip tasks with no files assigned
  for (const chunkFiles of chunks) {
    queue.push({
      task,
      chunk_files: chunkFiles,
      project_id: projectId,
      project_goal: projectGoal,
      plan_document: planDocument
    });
  }
}

const staticData = $getWorkflowStaticData('global');
