// ─── Deep summary extraction for non-task files ─────────────────────
function extractDeepSummary(content) {
  const parts = [];

  // Find contract-referenced types (createContext<T>, React.FC<T>)
  const referencedTypes = new Set();
  const ctxMatch = content.match(/createContext<(\w+)/);
  if (ctxMatch) referencedTypes.add(ctxMatch[1]);
  const fcMatches = content.matchAll(/React\.FC<(\w+)>/g);
  for (const m of fcMatches) referencedTypes.add(m[1]);
  const knownSuffixes = /(?:Props|Type|Context|State|Config)$/;

  // Exported AND contract-referenced interfaces with property names + types
  const interfaceRegex = /(?:export\s+)?(?:declare\s+)?interface\s+(\w+)\s*\{/g;
  let match;
  while ((match = interfaceRegex.exec(content)) !== null) {
    const name = match[1];
    const isExported = content.substring(Math.max(0, match.index - 10), match.index).includes('export');
    if (!isExported && !referencedTypes.has(name) && !knownSuffixes.test(name)) continue;
    const braceStart = match.index + match[0].length - 1;
    // Extract body using bracket depth
    let depth = 1;
    let i = braceStart + 1;
    while (i < content.length && depth > 0) {
      if (content[i] === '{') depth++;
      else if (content[i] === '}') depth--;
      i++;
    }
    const body = content.substring(braceStart + 1, i - 1).trim();
    // Extract property lines
    const props = body.split('\n')
      .map(l => l.trim())
      .filter(l => l && !l.startsWith('//') && !l.startsWith('/*'))
      .map(l => l.replace(/;$/, ''))
      .slice(0, 10);
    if (props.length > 0) {
      parts.push('interface ' + name + ' { ' + props.join('; ') + ' }');
    }
  }

  // Exported type aliases
  const typeRegex = /export\s+(?:declare\s+)?type\s+(\w+)\s*=\s*([^;]+);/g;
  while ((match = typeRegex.exec(content)) !== null) {
    parts.push('type ' + match[1] + ' = ' + match[2].trim().substring(0, 120));
  }

  // Function/const signatures with return types
  // export const foo = (params): ReturnType =>
  const constFnRegex = /export\s+const\s+(\w+)\s*=\s*(?:async\s+)?\(([^)]*)\)\s*(?::\s*([\w<>\[\],\s|&{}]+?))?\s*=>/g;
  while ((match = constFnRegex.exec(content)) !== null) {
    const ret = match[3] ? ': ' + match[3].trim() : '';
    parts.push(match[1] + '(' + match[2].substring(0, 80) + ')' + ret);
  }

  // export function foo(params): ReturnType
  const fnRegex = /export\s+(?:async\s+)?function\s+(\w+)\s*\(([^)]*)\)\s*(?::\s*([\w<>\[\],\s|&{}]+?))?[\s{]/g;
  while ((match = fnRegex.exec(content)) !== null) {
    const ret = match[3] ? ': ' + match[3].trim() : '';
    parts.push(match[1] + '(' + match[2].substring(0, 80) + ')' + ret);
  }

  // export default component with props type
  const fcRegex = /export\s+(?:default\s+)?(?:const|function)\s+(\w+)[\s:]*(?:React\.)?FC<(\w+)>/g;
  while ((match = fcRegex.exec(content)) !== null) {
    parts.push(match[1] + ': FC<' + match[2] + '>');
  }

  // Plain export default
  const defRegex = /export\s+default\s+(?:function\s+)?(\w+)/g;
  while ((match = defRegex.exec(content)) !== null) {
    if (!parts.some(p => p.includes(match[1]))) {
      parts.push('default ' + match[1]);
    }
  }

  // Exported classes
  const classRegex = /export\s+(?:default\s+)?class\s+(\w+)(?:\s+extends\s+(\w+))?/g;
  while ((match = classRegex.exec(content)) !== null) {
    const ext = match[2] ? ' extends ' + match[2] : '';
    if (!parts.some(p => p.includes(match[1]))) {
      parts.push('class ' + match[1] + ext);
    }
  }

  // Exported enums
  const enumRegex = /export\s+(?:const\s+)?enum\s+(\w+)/g;
  while ((match = enumRegex.exec(content)) !== null) {
    if (!parts.some(p => p.includes(match[1]))) {
      parts.push('enum ' + match[1]);
    }
  }

  // export { ... } re-exports
  const reExportRegex = /export\s+\{([^}]+)\}/g;
  while ((match = reExportRegex.exec(content)) !== null) {
    const names = match[1].split(',').map(n => n.trim().split(' as ')[0].trim()).filter(Boolean);
    for (const name of names) {
      if (!parts.some(p => p.startsWith(name) || p.includes(' ' + name))) {
        parts.push(name);
      }
    }
  }

  return parts;
}

// Split: full content for task files, compact for everything else
const fullFiles = [];
