    // Deep summary for TS/JS/TSX/JSX files
    if (file.path.match(/\.(ts|tsx|js|jsx)$/)) {
      const deepParts = extractDeepSummary(content);
      let summary;
      if (deepParts.length > 0) {
        summary = deepParts.join(' | ');
      } else {
