    // Find HTML files in references/
    const htmlRefs = refFiles.filter(f => f.path.startsWith('references/') && f.path.endsWith('.html'));

    for (const ref of htmlRefs.slice(0, 2)) {
      const content = ref.content || '';
      if (content.length < 100) continue;

      // Extract Tailwind config
      const configMatch = content.match(/tailwind\.config\s*=\s*(\{[\s\S]*?\})\s*<\/script>/);
      if (configMatch && !designSystem) {
        designSystem = configMatch[1].substring(0, 4000);
        staticData._stitchDesignSystem = designSystem;

          // Extract common component patterns from HTML and generate @apply classes
          const classPatterns = [];

          // Find repeated class combinations in the HTML (buttons, cards, badges, etc.)
          const classMatches = content.match(/class="([^"]{30,})"/g) || [];
          const classCounts = {};
          for (const match of classMatches) {
            const classes = match.replace('class="', '').replace('"', '').trim();
            // Normalize whitespace
            const normalized = classes.replace(/\s+/g, ' ').trim();
            classCounts[normalized] = (classCounts[normalized] || 0) + 1;
          }

          // Find patterns used 2+ times — these are component-worthy
          const componentClasses = [];
          for (const [classes, count] of Object.entries(classCounts)) {
            if (count >= 2 && classes.length > 20 && classes.length < 200) {
              // Generate a semantic name from the classes
              let name = 'component';
              if (classes.includes('rounded-full') && classes.includes('px-')) name = 'pill';
              else if (classes.includes('rounded-') && classes.includes('border')) name = 'card';
              else if (classes.includes('font-bold') && classes.includes('text-')) name = 'heading';
              else if (classes.includes('flex') && classes.includes('items-center')) name = 'row';
              else if (classes.includes('grid')) name = 'grid';
              else if (classes.includes('btn') || (classes.includes('cursor-pointer') && classes.includes('px-'))) name = 'btn';
              else if (classes.includes('backdrop-blur')) name = 'glass';

              componentClasses.push({ name: name + '-' + componentClasses.length, classes, count });
            }
          }

          if (componentClasses.length > 0) {
            // Generate @apply CSS
            let applyCSS = '@layer components {\n';
            for (const comp of componentClasses.slice(0, 15)) {
