let content = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
if (content.includes('</think>')) content = content.split('</think>').pop().trim();
if (content.length < 50 && reasoning.length > 50) {
  content = reasoning.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
  if (content.includes('</think>')) content = content.split('</think>').pop().trim();
}
if (content.length < 50 && raw.length > 50) {
  content = raw.replace(/<think>/g, '').replace(/<\/think>/g, '').trim();
}

const files = [];
const edits = [];
const seen = new Set();

// ── 1. Parse SEARCH/REPLACE blocks — use lastIndexOf for ======= separator ──
const blockRe = /(?:FILE:|###)?\s*([\w.\/-]+(?:\.[\w]+))\s*\n<<<<<<< SEARCH\n([\s\S]*?)\n>>>>>>> REPLACE/g;
let bm;
while ((bm = blockRe.exec(content)) !== null) {
  const path = bm[1].trim();
  const blockContent = bm[2];
  const lastSep = blockContent.lastIndexOf('\n=======\n');
  if (lastSep === -1) continue;
  const search = blockContent.substring(0, lastSep);
  const replace = blockContent.substring(lastSep + '\n=======\n'.length);
  edits.push({ path, search, replace });
}

// ── 2. Parse full file blocks (for new files) ──
const fileRe = /###\s+((?:[\w.-]+\/)*(?:\.[\w][\w.-]*|[\w.-]+\.(?:ts|tsx|js|jsx|json|md|yml|yaml|env|prisma|css|html|sh|txt|lock|toml|cfg|ini)|Dockerfile|Makefile|LICENSE|CHANGELOG))\s*\n```[\w]*\n([\s\S]*?)```/g;
let fm;
while ((fm = fileRe.exec(content)) !== null) {
  const path = fm[1].trim();
  const fileContent = fm[2];
  if (path && !seen.has(path)) {
    seen.add(path);
    files.push({ path, content: fileContent });
  }
}

// ── 3. Apply search/replace edits to existing file contents ──
const staticData = $getWorkflowStaticData('global');
const allFiles = staticData._allFileContents || [];

const editsByFile = {};
for (const edit of edits) {
  if (!editsByFile[edit.path]) editsByFile[edit.path] = [];
  editsByFile[edit.path].push(edit);
}

for (const [path, fileEdits] of Object.entries(editsByFile)) {
  if (seen.has(path)) continue;
  const existing = allFiles.find(f => f.path === path);
  if (!existing) continue;
  let fileContent = existing.content;
  let applied = 0;
  for (const edit of fileEdits) {
    if (fileContent.includes(edit.search)) {
      fileContent = fileContent.replace(edit.search, edit.replace);
      applied++;
    } else {
      const searchTrimmed = edit.search.split('\n').map(l => l.trim()).join('\n');
      const contentLines = fileContent.split('\n');
      for (let i = 0; i <= contentLines.length - edit.search.split('\n').length; i++) {
        const window = contentLines.slice(i, i + edit.search.split('\n').length);
        const windowTrimmed = window.map(l => l.trim()).join('\n');
        if (windowTrimmed === searchTrimmed) {
          const replaceLines = edit.replace.split('\n');
          contentLines.splice(i, edit.search.split('\n').length, ...replaceLines);
          fileContent = contentLines.join('\n');
          applied++;
          break;
        }
      }
